import{_ as r,o as t,c as p,j as e,a as n,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"钛帝国脉冲步枪","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/远程武器/2.C级/钛帝国脉冲步枪.md","filePath":"4.资源分区/7.物品与装备/2.武器/远程武器/2.C级/钛帝国脉冲步枪.md"}'),s={name:"4.资源分区/7.物品与装备/2.武器/远程武器/2.C级/钛帝国脉冲步枪.md"};function d(_,a,l,i,c,h){return t(),p("div",null,[...a[0]||(a[0]=[e("h1",{id:"钛帝国脉冲步枪",tabindex:"-1"},[n("钛帝国脉冲步枪 "),e("a",{class:"header-anchor",href:"#钛帝国脉冲步枪","aria-label":'Permalink to "钛帝国脉冲步枪"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘")])])],-1),o('<h1 id="钛帝国脉冲步枪-1" tabindex="-1">钛帝国脉冲步枪 <a class="header-anchor" href="#钛帝国脉冲步枪-1" aria-label="Permalink to &quot;钛帝国脉冲步枪&quot;">​</a></h1><p>钛帝国脉冲步枪<br> C+3000<br> 科技本质<br> 脉冲武器是钛帝国土氏族开发的一种等离子武器家族，其只被火氏族装备。脉冲步枪的工作原理是利用脉冲感应场推动等离子体的致命微脉冲在长射程距离下爆炸。</p><p>重量：1.75KG</p><p>长度：1200毫米</p><p>体积：3</p><p>专业：步枪</p><p>伤害：12L</p><p>持用：双手</p><p>基础射程：150米</p><p>脉冲武器的工作原理是使等离子体弹壳沿枪管以电磁加速方式加速。实际上，它是个微型质量加速器。发射时，将铁磁性的固体块从弹匣中放出来，并通过电磁感应将其转变成等离子体。将线圈电流以足够高的频率交替，使线圈加热到极端温度对于它来说是很容易的。然后，枪膛螺线管充满电，以极高的速度将新产生的等离子体从喷枪中推出，同时保持其粘结性。随后剩余的等离子体从枪管中喷出，产生相当大的枪口闪光。螺旋形电磁感应设备也有助于维持磁场，从而增加了磁场强度，继而增加射程。螺旋形电磁感应设备的重量也会进一步降低武器的后坐力。如果没有维持电磁场，那么发射的等离子体将全部消散在枪管口处，喷出约20厘米左右。正因为如此， 脉冲武器的射击除了需要实体弹药外，还需能量电池基于供能。</p><p>最大弹夹：36固体块。<br> 特殊的，每支持36发弹药射击需消耗一个标准电池，一个杂技动作或同时消耗一个移动动作和迅捷动作才能重新装填子弹。</p><p>连射等级：无</p><p>伤害类型：该武器通过释放离子脉冲，以用来气化敌人的装甲与肉体，这使得该武器具有【能量武器】特性。</p><p>为时已晚：脉冲枪采用两段式发射的方法来确保其等离子体弹药的命中——当扳机被扣到一半时，一束看不见的带负电荷的粒子会光速击中目标，然随后负电荷会引导全部的等离子体击中目标。这使得受害者在被击中前瞬间发出鬼魅般的光芒，如同死神的最后的垂怜。 人物在使用该武器攻击时，需先进行一次命中检定，若成功造成任何一个成功数，则可在真正的攻击中，忽略目标不超过5点的基础/闪避防御。</p><p>弹药<br> 铁磁性固体块：1分50发</p><p>---------------------------------------------------------------------------------------------------------------<br> “中士还没来得及发出警告就被嗡嗡作响的光束撕成了碎片。我甚至没有时间向帝皇祷告，他就什么都没有了，除了那双靴子。”——“幸运的”莱昂·卡德米翁（Leon ‘Lucky’ Cadmion）在达摩克里斯湾遭到一支秘密小队的伏击。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',18)])])}const m=r(s,[["render",d]]);export{f as __pageData,m as default};
